/** Get a localized chapter field. Falls back to English. */
export function chapterText(chapterId: number, field: keyof ChapterI18n, lang: Lang): string | string[] {
  const data = CHAPTER_I18N[chapterId];
  if (!data) return '';
  const val = data[field];
  return (val as Record<Lang, string | string[]>)[lang] ?? (val as Record<Lang, string | string[]>)['en'];
}
